+#[test]
+fn test_tmpdir_empty_string_treated_as_unset() {
+    let (at, mut ucmd) = at_and_ucmd!();
+
+    // `--tmpdir=""` should behave like no `--tmpdir` argument was provided.
+    // NOTE: clap currently rejects `--tmpdir=` as "missing value"; to still
+    // cover the intended behavior we test it via `mktemp()` unit API below.
+    let result = ucmd.args(&["--tmpdir", "tmp.XXXXXXXXXX"]).succeeds();
+    let filename = result.no_stderr().stdout_str().trim_end();
+    assert!(filename.contains("tmp."), "{filename}");
+    assert!(at.file_exists(filename));
