    78→
    79→/// Options parsed from the command-line.
    80→///
    81→/// This provides a layer of indirection between the application logic
    82→/// and the argument parsing library `clap`, allowing each to vary
    83→/// independently.
    84→#[derive(Clone)]
    85→pub struct Options {
    86→    /// Whether to create a temporary directory instead of a file.
    87→    pub directory: bool,
    88→
    89→    /// Whether to just print the name of a file that would have been created.
    90→    pub dry_run: bool,
    91→
    92→    /// Whether to suppress file creation error messages.
    93→    pub quiet: bool,
    94→
    95→    /// The directory in which to create the temporary file.
    96→    ///
    97→    /// If `None`, the file will be created in the current directory.
    98→    pub tmpdir: Option<PathBuf>,
    99→
   100→    /// The suffix to append to the temporary file, if any.
   101→    pub suffix: Option<String>,
   102→
   103→    /// Whether to treat the template argument as a single file path component.
   104→    pub treat_as_template: bool,
   105→
   106→    /// The template to use for the name of the temporary file.
   107→    pub template: String,
   108→}
   109→
   110→impl Options {
   111→    fn from(matches: &ArgMatches) -> Self {
   112→        let tmpdir = matches
   113→            .get_one::<PathBuf>(OPT_TMPDIR)
   114→            .or_else(|| matches.get_one::<PathBuf>(OPT_P))
   115→            .cloned();
   116→        let (tmpdir, template) = match matches.get_one::<String>(ARG_TEMPLATE) {
   117→            // If no template argument is given, `--tmpdir` is implied.
   118→            None => {
   119→                let tmpdir = Some(tmpdir.unwrap_or_else(env::temp_dir));
   120→                let template = DEFAULT_TEMPLATE;
   121→                (tmpdir, template.to_string())
   122→            }
   123→            Some(template) => {
   124→                let tmpdir = if env::var(TMPDIR_ENV_VAR).is_ok() && matches.get_flag(OPT_T) {
   125→                    env::var_os(TMPDIR_ENV_VAR).map(|t| t.into())
   126→                } else if tmpdir.is_some() {
   127→                    tmpdir
   128→                } else if matches.get_flag(OPT_T) || matches.contains_id(OPT_TMPDIR) {
   129→                    // If --tmpdir is given without an argument, or -t is given
   130→                    // export in TMPDIR
   131→                    Some(env::temp_dir())
   132→                } else {
   133→                    None
   134→                };
   135→                (tmpdir, template.to_string())
   136→            }
   137→        };
   138→        Self {
   139→            directory: matches.get_flag(OPT_DIRECTORY),
   140→            dry_run: matches.get_flag(OPT_DRY_RUN),
   141→            quiet: matches.get_flag(OPT_QUIET),
   142→            tmpdir,
   143→            suffix: matches.get_one::<String>(OPT_SUFFIX).map(String::from),
   144→            treat_as_template: matches.get_flag(OPT_T),
   145→            template,
   146→        }
   147→    }
   148→}
   149→
   150→/// Parameters that control the path to and name of the temporary file.
   151→///
   152→/// The temporary file will be created at
   153→///
   154→/// ```text
   155→/// {directory}/{prefix}{XXX}{suffix}
   156→/// ```
   157→///
   158→/// where `{XXX}` is a sequence of random characters whose length is
   159→/// `num_rand_chars`.
   160→struct Params {
   161→    /// The directory that will contain the temporary file.
   162→    directory: PathBuf,
   163→
   164→    /// The (non-random) prefix of the temporary file.
   165→    prefix: String,
   166→
   167→    /// The number of random characters in the name of the temporary file.
   168→    num_rand_chars: usize,
   169→
   170→    /// The (non-random) suffix of the temporary file.
   171→    suffix: String,
   172→}
   173→
   174→/// Find the start and end indices of the last contiguous block of Xs.
   175→///
   176→/// If no contiguous block of at least three Xs could be found, this
   177→/// function returns `None`.
   178→///
   179→/// # Examples
   180→///
   181→/// ```rust,ignore
   182→/// assert_eq!(find_last_contiguous_block_of_xs("XXX_XXX"), Some((4, 7)));
   183→/// assert_eq!(find_last_contiguous_block_of_xs("aXbXcX"), None);
   184→/// ```
   185→fn find_last_contiguous_block_of_xs(s: &str) -> Option<(usize, usize)> {
   186→    let j = s.rfind("XXX")? + 3;
   187→    let i = s[..j].rfind(|c| c != 'X').map_or(0, |i| i + 1);
   188→    Some((i, j))
   189→}
   190→
   191→impl Params {
   192→    fn from(options: Options) -> Result<Self, MkTempError> {
   193→        // The template argument must end in 'X' if a suffix option is given.
   194→        if options.suffix.is_some() && !options.template.ends_with('X') {
   195→            return Err(MkTempError::MustEndInX(options.template));
   196→        }
   197→
   198→        // Get the start and end indices of the randomized part of the template.
   199→        //
   200→        // For example, if the template is "abcXXXXyz", then `i` is 3 and `j` is 7.
   201→        let Some((i, j)) = find_last_contiguous_block_of_xs(&options.template) else {
   202→            let s = match options.suffix {
   203→                // If a suffix is specified, the error message includes the template without the suffix.
   204→                Some(_) => options
   205→                    .template
   206→                    .chars()
   207→                    .take(options.template.len())
   208→                    .collect::<String>(),
   209→                None => options.template,
   210→            };
   211→            return Err(MkTempError::TooFewXs(s));
   212→        };
   213→
   214→        // Combine the directory given as an option and the prefix of the template.
   215→        //
   216→        // For example, if `tmpdir` is "a/b" and the template is "c/dXXX",
   217→        // then `prefix` is "a/b/c/d".
   218→        let tmpdir = options.tmpdir;
   219→        let prefix_from_option = tmpdir.clone().unwrap_or_default();
   220→        let prefix_from_template = &options.template[..i];
   221→        let prefix = Path::new(&prefix_from_option)
   222→            .join(prefix_from_template)
   223→            .display()
   224→            .to_string();
   225→        if options.treat_as_template && prefix_from_template.contains(MAIN_SEPARATOR) {
   226→            return Err(MkTempError::PrefixContainsDirSeparator(options.template));
   227→        }
   228→        if tmpdir.is_some() && Path::new(prefix_from_template).is_absolute() {
   229→            return Err(MkTempError::InvalidTemplate(options.template));
   230→        }
   231→
   232→        // Split the parent directory from the file part of the prefix.
   233→        //
   234→        // For example, if `prefix` is "a/b/c/d", then `directory` is
   235→        // "a/b/c" is `prefix` gets reassigned to "d".
   236→        let (directory, prefix) = if prefix.ends_with(MAIN_SEPARATOR) {
   237→            (prefix, String::new())
   238→        } else {
   239→            let path = Path::new(&prefix);
   240→            let directory = match path.parent() {
   241→                None => String::new(),
   242→                Some(d) => d.display().to_string(),
   243→            };
   244→            let prefix = match path.file_name() {
   245→                None => String::new(),
   246→                Some(f) => f.to_str().unwrap().to_string(),
   247→            };
   248→            (directory, prefix)
   249→        };
   250→
   251→        // Combine the suffix from the template with the suffix given as an option.
   252→        //
   253→        // For example, if the suffix command-line argument is ".txt" and
   254→        // the template is "XXXabc", then `suffix` is "abc.txt".
   255→        let suffix_from_option = options.suffix.unwrap_or_default();
   256→        let suffix_from_template = &options.template[j..];
   257→        let suffix = format!("{suffix_from_template}{suffix_from_option}");
   258→        if suffix.contains(MAIN_SEPARATOR) {
   259→            return Err(MkTempError::SuffixContainsDirSeparator(suffix));
   260→        }
   261→
   262→        // The number of random characters in the template.
   263→        //
   264→        // For example, if the template is "abcXXXXyz", then the number of
   265→        // random characters is four.
   266→        let num_rand_chars = j - i;
   267→
   268→        Ok(Self {
   269→            directory: directory.into(),
   270→            prefix,
   271→            num_rand_chars,
   272→            suffix,
   273→        })
   274→    }
   275→}
