   277→#[uucore::main]
   278→pub fn uumain(args: impl uucore::Args) -> UResult<()> {
   279→    let args: Vec<_> = args.collect();
   280→    let matches = match uu_app().try_get_matches_from(&args) {
   281→        Ok(m) => m,
   282→        Err(e) => {
   283→            if e.kind() == clap::error::ErrorKind::TooManyValues
   284→                && e.context().any(|(kind, val)| {
   285→                    kind == clap::error::ContextKind::InvalidArg
   286→                        && val == &clap::error::ContextValue::String("[template]".into())
   287→                })
   288→            {
   289→                return Err(UUsageError::new(
   290→                    1,
   291→                    translate!("mktemp-error-too-many-templates"),
   292→                ));
   293→            }
   294→            return Err(e.into());
   295→        }
   296→    };
   297→
   298→    // Parse command-line options into a format suitable for the
   299→    // application logic.
   300→    let options = Options::from(&matches);
   301→
   302→    if env::var("POSIXLY_CORRECT").is_ok() {
   303→        // If POSIXLY_CORRECT was set, template MUST be the last argument.
   304→        if matches.contains_id(ARG_TEMPLATE) {
   305→            // Template argument was provided, check if was the last one.
   306→            if args.last().unwrap() != OsStr::new(&options.template) {
   307→                return Err(Box::new(MkTempError::TooManyTemplates));
   308→            }
   309→        }
   310→    }
   311→
   312→    let dry_run = options.dry_run;
   313→    let suppress_file_err = options.quiet;
   314→    let make_dir = options.directory;
   315→
   316→    // Parse file path parameters from the command-line options.
   317→    let Params {
   318→        directory: tmpdir,
   319→        prefix,
   320→        num_rand_chars: rand,
   321→        suffix,
   322→    } = Params::from(options)?;
   323→
   324→    // Create the temporary file or directory, or simulate creating it.
   325→    let res = if dry_run {
   326→        dry_exec(&tmpdir, &prefix, rand, &suffix)
   327→    } else {
   328→        exec(&tmpdir, &prefix, rand, &suffix, make_dir)
   329→    };
   330→
   331→    let res = if suppress_file_err {
   332→        // Mapping all UErrors to ExitCodes prevents the errors from being printed
   333→        res.map_err(|e| e.code().into())
   334→    } else {
   335→        res
   336→    };
   337→    println_verbatim(res?).map_err_context(|| translate!("mktemp-error-failed-print"))
   338→}
   339→
   340→pub fn uu_app() -> Command {
   341→    Command::new(uucore::util_name())
   342→        .version(uucore::crate_version!())
   343→        .about(translate!("mktemp-about"))
   344→        .override_usage(format_usage(&translate!("mktemp-usage")))
   345→        .infer_long_args(true)
   346→        .arg(
   347→            Arg::new(OPT_DIRECTORY)
   348→                .short('d')
   349                .long(OPT_DIRECTORY)
   350→                .help(translate!("mktemp-help-directory"))
   351→                .action(ArgAction::SetTrue),
   352→        )
   353→        .arg(
   354→            Arg::new(OPT_DRY_RUN)
   355→                .short('u')
   356→                .long(OPT_DRY_RUN)
   357→                .help(translate!("mktemp-help-dry-run"))
   358→                .action(ArgAction::SetTrue),
   359→        )
   360→        .arg(
   361→            Arg::new(OPT_QUIET)
   362→                .short('q')
   363→                .long("quiet")
   364→                .help(translate!("mktemp-help-quiet"))
   365→                .action(ArgAction::SetTrue),
   366→        )
   367→        .arg(
   368→            Arg::new(OPT_SUFFIX)
   369→                .long(OPT_SUFFIX)
   370→                .help(translate!("mktemp-help-suffix"))
   371→                .value_name("SUFFIX"),
   372→        )
   373→        .arg(
   374→            Arg::new(OPT_P)
   375→                .short('p')
   376→                .help(translate!("mktemp-help-p"))
   377→                .value_name("DIR")
   378→                .num_args(1)
   379→                .value_parser(ValueParser::path_buf())
   380→                .value_hint(clap::ValueHint::DirPath),
   381→        )
   382→        .arg(
   383→            Arg::new(OPT_TMPDIR)
   384→                .long(OPT_TMPDIR)
   385→                .help(translate!("mktemp-help-tmpdir"))
   386→                .value_name("DIR")
   387→                // Allows use of default argument just by setting --tmpdir. Else,
   388→                // use provided input to generate tmpdir
   389→                .num_args(0..=1)
   390→                // Require an equals to avoid ambiguity if no tmpdir is supplied
   391→                .require_equals(true)
   392→                .overrides_with(OPT_P)
   393→                .value_parser(ValueParser::path_buf())
   394→                .value_hint(clap::ValueHint::DirPath),
   395→        )
   396→        .arg(
   397→            Arg::new(OPT_T)
   398→                .short('t')
   399→                .help(translate!("mktemp-help-t"))
   400→                .action(ArgAction::SetTrue),
   401→        )
   402→        .arg(Arg::new(ARG_TEMPLATE).num_args(..=1))
   403→}
   404→
   405→fn dry_exec(tmpdir: &Path, prefix: &str, rand: usize, suffix: &str) -> UResult<PathBuf> {
   406→    let len = prefix.len() + suffix.len() + rand;
   407→    let mut buf = Vec::with_capacity(len);
   408→    buf.extend(prefix.as_bytes());
   409→    buf.extend(iter::repeat_n(b'X', rand));
   410→    buf.extend(suffix.as_bytes());
   411→
   412→    // Randomize.
   413→    let bytes = &mut buf[prefix.len()..prefix.len() + rand];
   414→    rand::rng().fill(bytes);
   415→    for byte in bytes {
   416→        *byte = match *byte % 62 {
   417→            v @ 0..=9 => v + b'0',
   418→            v @ 10..=35 => v - 10 + b'a',
   419→            v @ 36..=61 => v - 36 + b'A',
   420→            _ => unreachable!(),
   421→        }
   422→    }
   423→    // We guarantee utf8.
   424→    let buf = String::from_utf8(buf).unwrap();
   425→    let tmpdir = Path::new(tmpdir).join(buf);
   426→    Ok(tmpdir)
   427→}
   428→
   429→/// Create a temporary directory with the given parameters.
   430→///
   431→/// This function creates a temporary directory as a subdirectory of
   432→/// `dir`. The name of the directory is the concatenation of `prefix`,
   433→/// a string of `rand` random characters, and `suffix`. The
   434→/// permissions of the directory are set to `u+rwx`
   435→///
   436→/// # Errors
   437→///
   438→/// If the temporary directory could not be written to disk or if the
   439→/// given directory `dir` does not exist.
   440→fn make_temp_dir(dir: &Path, prefix: &str, rand: usize, suffix: &str) -> UResult<PathBuf> {
   441→    let mut builder = Builder::new();
   442→    builder.prefix(prefix).rand_bytes(rand).suffix(suffix);
   443→
   444→    // On *nix platforms grant read-write-execute for owner only.
   445→    // The directory is created with these permission at creation time, using mkdir(3) syscall.
   446→    // This is not relevant on Windows systems. See: https://docs.rs/tempfile/latest/tempfile/#security
   447→    // `fs` is not imported on Windows anyways.
   448→    #[cfg(not(windows))]
   449→    builder.permissions(fs::Permissions::from_mode(0o700));
   450→
   451→    match builder.tempdir_in(dir) {
   452→        Ok(d) => {
   453→            // `keep` consumes the TempDir without removing it
   454→            let path = d.keep();
   455→            Ok(path)
   456→        }
   457→        Err(e) if e.kind() == ErrorKind::NotFound => {
   458→            let filename = format!("{prefix}{}{suffix}", "X".repeat(rand));
   459→            let path = Path::new(dir).join(filename);
   460→            let s = path.display().to_string();
   461→            Err(MkTempError::NotFound(translate!("mktemp-template-type-directory"), s).into())
   462→        }
   463→        Err(e) => Err(e.into()),
   464→    }
   465→}
   466→
   467→/// Create a temporary file with the given parameters.
   468→///
   469→/// This function creates a temporary file in the directory `dir`. The
   470→/// name of the file is the concatenation of `prefix`, a string of
   471→/// `rand` random characters, and `suffix`. The permissions of the
   472→/// file are set to `u+rw`.
   473→///
   474→/// # Errors
   475→///
   476→/// If the file could not be written to disk or if the directory does
   477→/// not exist.
   478→fn make_temp_file(dir: &Path, prefix: &str, rand: usize, suffix: &str) -> UResult<PathBuf> {
   479→    let mut builder = Builder::new();
   480→    builder.prefix(prefix).rand_bytes(rand).suffix(suffix);
   481→    match builder.tempfile_in(dir) {
   482→        // `keep` ensures that the file is not deleted
   483→        Ok(named_tempfile) => match named_tempfile.keep() {
   484→            Ok((_, pathbuf)) => Ok(pathbuf),
   485→            Err(e) => Err(MkTempError::PersistError(e.file.path().to_path_buf()).into()),
   486→        },
