   494→    }
   495→}
   496→
   497→fn exec(dir: &Path, prefix: &str, rand: usize, suffix: &str, make_dir: bool) -> UResult<PathBuf> {
   498→    let path = if make_dir {
   499→        make_temp_dir(dir, prefix, rand, suffix)?
