    39→/// An assertion that uses [`matches_template`] and adds a helpful error message.
    40→macro_rules! assert_matches_template {
    41→    ($template:expr, $s:expr) => {{
    42→        assert!(
    43→            matches_template($template, $s),
    44→            "\"{}\" != \"{}\"",
    45→            $template,
    46→            $s
    47→        );
    48→    }};
    49→}
    50→
    51→/// Like [`assert_matches_template`] but for the suffix of a string.
    52→#[cfg(windows)]
    53→macro_rules! assert_suffix_matches_template {
    54→    ($template:expr, $s:expr) => {{
    55→        let n = ($s).len();
    56→        let m = ($template).len();
    57→        let suffix = &$s[n - m..n];
    58→        assert!(
    59→            matches_template($template, suffix),
    60→            "\"{}\" does not end with \"{suffix}\"",
    61→            $template,
    62→        );
    63→    }};
    64→}
