   486→/// Decide whether a string matches a given template.
   487→///
   488→/// In the template, the character `'X'` is treated as a wildcard,
   489→/// that is, it matches anything. All other characters in `template`
   490→/// and `s` must match exactly.
   491→///
   492→/// # Examples
   493→///
   494→/// ```rust,ignore
   495→/// # These all match.
   496→/// assert!(matches_template("abc", "abc"));
   497→/// assert!(matches_template("aXc", "abc"));
   498→/// assert!(matches_template("XXX", "abc"));
   499→///
   500→/// # None of these match
   501→/// assert!(matches_template("abc", "abcd"));
   502→/// assert!(matches_template("abc", "ab"));
   503→/// assert!(matches_template("aXc", "abd"));
   504→/// assert!(matches_template("XXX", "abcd"));
   505→/// ```
   506→///
   507→fn matches_template(template: &str, s: &str) -> bool {
   508→    if template.len() != s.len() {
   509→        return false;
   510→    }
   511→    for (a, b) in template.chars().zip(s.chars()) {
   512→        if !(a == 'X' || a == b) {
   513→            return false;
   514→        }
   515→    }
   516→    true
   517→}
