#[test]
fn test_tmpdir_empty_string_treated_as_unset() {
    let (at, mut ucmd) = at_and_ucmd!();

    // `-p ""` should behave like no `-p` was provided at all.
    // Note: pass it as `-p=` to ensure the empty string is preserved
    // through the test harness argument handling.
    let result = ucmd.args(&["-p="]).succeeds();
    let filename = result.no_stderr().stdout_str().trim_end();
    assert!(at.file_exists(filename));

    let (at, mut ucmd) = at_and_ucmd!();

    // `--tmpdir=""` should behave like no `--tmpdir` argument was provided.
    let result = ucmd.args(&["--tmpdir=", "XXX"]).succeeds();
    let filename = result.no_stderr().stdout_str().trim_end();
    assert_matches_template!("XXX", filename);
    assert!(at.file_exists(filename));
}

