fn test_mktemp_tmpdir_empty_string_treated_as_unset() {
    let options = Options {
        directory: false,
        dry_run: true,
        quiet: false,
        // This simulates `--tmpdir=""` / `-p ""`.
        tmpdir: Some("".into()),
        suffix: None,
        treat_as_template: true,
        template: "tmp.XXX".into(),
    };

    let path = mktemp(&options).unwrap();
    // Should fall back to the default temp dir rather than using the
    // empty string as a directory.
    assert!(path.to_string_lossy().contains("tmp."));
}

